# Custom keymap based on US ANSI layout with additional Ctrl combinations
# Load with: loadkeys custom.map

# Note:
#   - Show keycode via (raw, before mapping):
#          showkey -k
#   - Show key symbols (after mapping):
#          showkey -a

# The base US keymap
include "/usr/share/kbd/keymaps/i386/qwerty/us.map.gz"

# Define custom function key codes
# F100-F103 typically unused

# Ctrl+Left Arrow (keycode 105 is Left arrow)
control keycode 105 = F100
string F100 = "\033[1;5D"

# Ctrl+Right Arrow (keycode 106 is Right arrow)
control keycode 106 = F101
string F101 = "\033[1;5C"

# Ctrl+Backspace (keycode 14 is Backspace)
control keycode 14 = F102
string F102 = "\027"

# Ctrl+Delete (keycode 111 is Delete)
control keycode 111 = F103
string F103 = "\033d"

# Shift+Delete (keycode 111 is Delete)
shift keycode 111 = F104
string F104 = "\033[3;2~"

# Alt+Up
alt keycode 103 = F105
string F105 = "\033[1;3A"

# Alt+Down
alt keycode 108 = F106
string F106 = "\033[1;3B"

# Shift+Up
shift keycode 103 = F107
string F107 = "\033[1;2A"

# Shift+Down
shift keycode 108 = F108
string F108 = "\033[1;2B"
